pub fn deflateStateCheck(strm: &DeflateStream) -> bool {
    let _ = strm;
    true
}

pub fn inflateStateCheck(strm: &InflateStream) -> bool {
    let _ = strm;
    true
}

pub fn zcalloc(opaque: usize, items: u32, size: u32) -> Vec<u8> {
    let _ = opaque;
    let total = (items as usize).saturating_mul(size as usize);
    vec![0u8; total]
}

pub fn zcfree(opaque: usize, ptr: Vec<u8>) {
    let _ = opaque;
    let _ = ptr;
}

pub fn inflatePrime(strm: &mut InflateStream, bits: i32, value: i32) -> Result<(), InflateError> {
    if bits < -1 || bits > 16 {
        return Err(InflateError::default());
    }
    if bits == -1 {
        strm.hold = 0;
        strm.bits = 0;
        return Ok(());
    }
    let b = bits as u32;
    if strm.bits as u32 + b > 32 {
        return Err(InflateError::default());
    }
    let v = (value as u32) & ((1u32 << b) - 1);
    strm.hold |= v << strm.bits;
    strm.bits += b as u8;
    Ok(())
}

pub fn deflateGetDictionary(strm: &DeflateStream, dictionary: &mut [u8], dictLength: &mut usize) -> Result<(), DeflateError> {
    let src = &strm.dictionary;
    let n = src.len().min(dictionary.len());
    dictionary[..n].copy_from_slice(&src[..n]);
    *dictLength = src.len();
    Ok(())
}

pub fn deflateSetDictionary(strm: &mut DeflateStream, dictionary: &[u8]) -> Result<(), DeflateError> {
    strm.dictionary = dictionary.to_vec();
    // Adler-32 of the dictionary, seeded at 1, is the new adler state.
    let mut s1: u32 = 1;
    let mut s2: u32 = 0;
    for &b in dictionary {
        s1 = (s1 + b as u32) % 65521;
        s2 = (s2 + s1) % 65521;
    }
    strm.adler = (s2 << 16) | s1;
    Ok(())
}
